    def test_doctor_status_only_omits_pass_findings_and_summarizes_details(self):
        result = {
            "status": "warn",
            "summary": "Monorepo health checks completed.",
            "findings": [
                {"status": "pass", "check": "repo.git", "message": "ok"},
                {
                    "status": "warn",
                    "check": "surface.deferred",
                    "message": "deferred",
                    "details": {"commands": ["one", "two"], "status": "known"},
                },
            ],
        }

        compact = turbovasctl.doctor_status_only_result(result)

        self.assertEqual(compact["details"], {"finding_count": 2, "non_pass_count": 1})
        self.assertEqual(len(compact["findings"]), 1)
        self.assertEqual(compact["findings"][0]["check"], "surface.deferred")
        self.assertEqual(compact["findings"][0]["details"]["commands"], {"type": "list", "count": 2})
        self.assertEqual(compact["findings"][0]["details"]["status"], "known")

    def test_production_posture_status_only_omits_pass_findings(self):
        result = {
            "status": "fail",
            "summary": "Production posture checklist completed.",
            "details": {"public_release_license_gate": {"status": "pass", "summary": "ok"}},
            "findings": [
                {"status": "pass", "check": "production.docs", "message": "ok"},
                {
                    "status": "fail",
                    "check": "production.tls",
                    "message": "missing TLS",
                    "details": {"cert_files": ["a", "b"]},
                },
            ],
        }

        compact = turbovasctl.production_posture_status_only_result(result)

        self.assertEqual(compact["details"], {"finding_count": 2, "non_pass_count": 1, "public_release_license_status": "pass"})
        self.assertEqual(compact["findings"][0]["check"], "production.tls")
        self.assertEqual(compact["findings"][0]["details"]["cert_files"], {"type": "list", "count": 2})

    def test_production_posture_status_only_redacts_sensitive_paths(self):
        result = {
            "status": "fail",
            "summary": "Production posture checklist completed.",
            "details": {"public_release_license_gate": {"status": "pass", "summary": "ok"}},
            "findings": [
                {
                    "status": "fail",
                    "check": "production.default-credentials",
                    "message": "default password",
                    "path": "/home/user/TurboVAS-runtime/secrets/gvmd-admin-password",
                    "details": {
                        "token_path": "/tmp/native-api-token",
                        "safe_count": 1,
                    },
                }
            ],
        }

        compact = turbovasctl.production_posture_status_only_result(result)

        self.assertEqual(compact["findings"][0]["path"], "[redacted]")
        self.assertEqual(compact["findings"][0]["details"]["token_path"], "[redacted]")
        self.assertEqual(compact["findings"][0]["details"]["safe_count"], 1)
        self.assertNotIn("gvmd-admin-password", json.dumps(compact))
        self.assertNotIn("native-api-token", json.dumps(compact))

    def test_native_api_migration_matrix_combines_inventory_and_openapi_metadata(self):
        root = Path(__file__).resolve().parents[2]
        result = turbovasctl.command_native_api_migration_matrix(root)
        details = result["details"]
        rows = {(item["method"], item["endpoint"]): item for item in details["items"]}
        findings = {item["check"]: item for item in result["findings"]}
        source = (Path(__file__).resolve().parents[1] / "turbovasctl").read_text(encoding="utf-8")

        self.assertEqual(result["status"], "pass")
        self.assertEqual(details["summary"]["total_rows"], 186)
        self.assertEqual(details["summary"]["openapi_operation_rows"], 186)
        self.assertEqual(details["summary"]["inventory_rows"], 186)
        self.assertEqual(details["summary"]["rows_with_checked_migration_metadata"], 186)
        self.assertEqual(details["summary"]["checked_migration_field_counts"]["x_turbovas_exposure"], 186)
        self.assertEqual(details["summary"]["rows_missing_openapi_count"], 0)
        self.assertEqual(details["summary"]["rows_missing_inventory_count"], 0)
        self.assertEqual(details["summary"]["rows_missing_migration_metadata_count"], 0)
        self.assertEqual(details["summary"]["direct_exposure_mismatch_count"], 0)
        self.assertEqual(details["summary"]["direct_marker_mismatch_count"], 0)
        self.assertEqual(findings["native-api-migration-matrix.coverage"]["status"], "pass")
        self.assertEqual(findings["native-api-migration-matrix.metadata"]["status"], "pass")
        self.assertIn("native-api-migration-matrix", source)
