        def fake_direct(_root, path, **kwargs):
            captured.append((path, kwargs))
            body = json.loads(kwargs["body"])
            if path == "/api/v1/port-lists":
                self.assertEqual(body["port_ranges"][0]["protocol"], "tcp")
                return subprocess.CompletedProcess(["curl"], 0, '{"id":"11111111-1111-4111-8111-111111111111","name":"Web"}\n201', "")
            self.assertEqual(path, "/api/v1/targets")
            self.assertEqual(body["port_list_id"], "11111111-1111-4111-8111-111111111111")
            self.assertEqual(body["alive_tests"], ["Scan Config Default"])
            self.assertNotIn("credentials", body)
            target_id = next(target_ids)
            return subprocess.CompletedProcess(["curl"], 0, json.dumps({"id": target_id, "name": body["name"]}) + "\n201", "")

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            hosts_file = root / "hosts.txt"
            hosts_file.write_text("192.0.2.10\n192.0.2.11\n", encoding="utf-8")
            with unittest.mock.patch.object(turbovasctl, "native_api_direct_runtime_env", return_value={}), \
                unittest.mock.patch.object(turbovasctl, "native_api_direct_config_shape_finding", return_value=turbovasctl.finding("pass", "direct-config", "ok")), \
                unittest.mock.patch.object(turbovasctl, "native_api_direct_bearer_token", return_value="a" * 64), \
                unittest.mock.patch.object(turbovasctl, "direct_native_api_curl", side_effect=fake_direct):
                result = turbovasctl.command_native_targets_from_host_list(
                    root,
                    hosts_file,
                    port_range="T:1-443",
                    port_list_name="Web",
                    allow_write_control=True,
                    status_only=True,
                )

        self.assertEqual(result["status"], "pass")
        self.assertEqual([path for path, _kwargs in captured], ["/api/v1/port-lists", "/api/v1/targets", "/api/v1/targets"])
        self.assertEqual(result["details"]["created_target_count"], 2)
        self.assertTrue(result["details"]["port_list_created"])

