    def run_mocked_feed_generation_transition(
        self,
        *,
        target_id="a" * 64,
        current_id="b" * 64,
        import_statuses=("pass",),
        post_verify_id="a" * 64,
        stop_statuses=("pass", "pass"),
        allow_first_activation=False,
        rollback=False,
        activation_state_override=None,
        scan_quiescence_status="pass",
        select_error=False,
        journal_error=False,
        repair_attestation=False,
        database_attestation="matching",
        running_services=None,
        phase_interrupt=None,
    ):
        image_ids = {
            service: "sha256:" + f"{index + 1:x}" * 64
            for index, service in enumerate(turbovasctl.APP_SERVICES)
        }
        runtime_artifacts = {
            "schema_version": 1,
            "algorithm": "sha256",
            "digest": "d" * 64,
            "entry_count": 7,
            "byte_count": 1024,
            "roots": [
                str(path)
                for path in (
                    *turbovasctl.APP_RUNTIME_ARTIFACT_ROOTS,
                    *turbovasctl.APP_RUNTIME_ARTIFACT_FILES,
                )
            ],
        }
        compose_contract = {
            "schema_version": 1,
            "algorithm": "sha256",
            "digest": "e" * 64,
            "services": list(turbovasctl.APP_SERVICES),
        }
        current = (
            {"generation_id": current_id, "verified": True}
            if current_id is not None
            else None
        )
        activation_state = (
            {
                "schema_version": 1,
                "status": "active",
                "current_generation_id": current_id,
                "target_generation_id": None,
                "previous_generation_id": None,
                "rollback_generation_id": "c" * 64,
            }
            if current_id is not None
            else None
        )
        if activation_state_override == "missing":
            activation_state = None
        elif activation_state_override is not None:
            activation_state = dict(activation_state_override)
            if activation_state.get("status") == "transitioning":
                activation_state.setdefault("app_image_ids", image_ids)
                activation_state.setdefault("app_runtime_artifacts", runtime_artifacts)
                activation_state.setdefault("app_compose_contract", compose_contract)
        import_results = [
            {
                "status": status,
                "summary": f"Mock feed import {status}.",
                "findings": [],
                "artifacts": [],
            }
            for status in import_statuses
        ]
        read_results = [current]
        if select_error:
            read_results.append(current)
        elif import_statuses[0] == "pass":
            read_results.append(
                {"generation_id": post_verify_id, "verified": True}
                if post_verify_id is not None
                else None
            )
        if len(import_statuses) > 1 or post_verify_id != target_id:
            compensation_id = target_id if rollback else current_id
            read_results.append(
                {"generation_id": compensation_id, "verified": True}
                if compensation_id is not None
                else None
            )
        stopped = unittest.mock.Mock(
            side_effect=[
                turbovasctl.finding(
                    status,
                    "feed-generation.stop",
                    f"Mock app services stop {status}.",
                )
                for status in stop_statuses
            ]
        )
        if select_error:
            selected = unittest.mock.Mock(
                side_effect=turbovasctl.FeedGenerationError("mock selection failure")
            )
        else:
            selected = unittest.mock.Mock(
                side_effect=lambda _root, generation, *_args: {
                    "generation_id": generation,
                    "current_generation_id": generation,
                    "previous_generation_id": current_id,
                }
            )
        cleared = unittest.mock.Mock()
        imported = unittest.mock.Mock(side_effect=import_results)
        scan_statuses = (
            list(scan_quiescence_status)
            if isinstance(scan_quiescence_status, tuple)
            else [scan_quiescence_status, scan_quiescence_status]
        )
        scan_quiescence = unittest.mock.Mock(
            side_effect=[
                turbovasctl.finding(
                    status,
                    "feed-generation.active-scans",
                    f"Mock scan quiescence {status}.",
                )
                for status in scan_statuses
            ]
        )
        journal_write = unittest.mock.Mock(
            side_effect=OSError("mock journal durability failure")
            if journal_error
            else None
        )
        database_attestation_write = unittest.mock.Mock(
            side_effect=lambda _root, generation, completed_at: turbovasctl.feed_generation_db_attestation_payload(
                generation, completed_at
            )
        )
        if database_attestation == "matching":
            database_attestation_value = (
                turbovasctl.feed_generation_db_attestation_payload(
                    current_id, "2026-07-13T00:00:00+00:00"
                )
                if current_id is not None
                else None
            )
            database_attestation_read = unittest.mock.Mock(
                return_value=database_attestation_value
            )
        elif database_attestation == "missing":
            database_attestation_read = unittest.mock.Mock(return_value=None)
        elif database_attestation == "mismatch":
            database_attestation_read = unittest.mock.Mock(
                return_value=turbovasctl.feed_generation_db_attestation_payload(
                    "d" * 64, "2026-07-13T00:00:00+00:00"
                )
            )
        elif isinstance(database_attestation, BaseException):
            database_attestation_read = unittest.mock.Mock(
                side_effect=database_attestation
            )
        else:
            database_attestation_read = unittest.mock.Mock(
                return_value=database_attestation
            )
        running_service_set = set(
            turbovasctl.APP_SERVICES
            if running_services is None
            else running_services
        )
        runtime_restart = unittest.mock.Mock(
            return_value={
                "status": "pass",
                "summary": "Mock feed runtime verified.",
                "findings": [],
                "artifacts": [],
            }
        )
        phase_events = []

        class MockTransitionInterruption(BaseException):
            pass

        def transition_phase(phase, details):
            phase_events.append((phase, details))
            if phase == phase_interrupt:
                raise MockTransitionInterruption(phase)
        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp) / "TurboVAS"
            root.mkdir()
            with unittest.mock.patch.multiple(
                turbovasctl,
                verify_generation=unittest.mock.Mock(
                    return_value={"generation_id": target_id, "verified": True}
                ),
                read_current_generation=unittest.mock.Mock(
                    side_effect=read_results
                ),
                read_feed_activation_state=unittest.mock.Mock(
                    return_value=activation_state
                ),
                write_feed_activation_state=journal_write,
                read_feed_generation_db_attestation=database_attestation_read,
                write_feed_generation_db_attestation=database_attestation_write,
                feed_activation_scan_quiescence_finding=scan_quiescence,
                stop_feed_control_services_for_preflight=unittest.mock.Mock(
                    return_value=turbovasctl.finding(
                        "pass",
                        "feed-generation.control-quiesce",
                        "Mock control services stopped.",
                        details={"previously_running_services": ["gvmd"]},
                    )
                ),
                restart_feed_control_services_after_preflight=unittest.mock.Mock(
                    return_value=turbovasctl.finding(
                        "pass",
                        "feed-generation.control-restore",
                        "Mock control services restored.",
                    )
                ),
                stop_app_services_for_feed_transition=stopped,
                feed_transition_phase=unittest.mock.Mock(
                    side_effect=transition_phase
                ),
                select_generation=selected,
                clear_current_generation=cleared,
                command_runtime_feed_import_init=imported,
                restart_and_verify_feed_app_services=runtime_restart,
                container_running=unittest.mock.Mock(
                    side_effect=lambda _root, service: service
                    in running_service_set
                ),
                feed_transition_restore_app_env=unittest.mock.Mock(
                    return_value={
                        turbovasctl.GSAD_HOSTS_ENV: "192.168.178.42,100.80.139.13"
                    }
                ),
                require_app_deployment_receipt=unittest.mock.Mock(
                    return_value=(
                        {
                            "schema_version": 1,
                            "image_ids": image_ids,
                            "runtime_artifacts": runtime_artifacts,
                            "compose_contract": compose_contract,
                            "prepared_at": "2026-07-13T00:00:00+00:00",
                        },
                        None,
                    )
                ),
                app_service_image_findings=unittest.mock.Mock(
                    return_value=[
                        turbovasctl.finding(
                            "pass",
                            "feed-generation.running-app-image",
                            f"Mock {service} image matches.",
                        )
                        for service in turbovasctl.APP_SERVICES
                    ]
                ),
                resolve_app_service_image_ids=unittest.mock.Mock(
                    return_value=(image_ids, None)
                ),
                app_service_image_availability_error=unittest.mock.Mock(
                    return_value=None
                ),
                app_runtime_artifact_manifest=unittest.mock.Mock(
                    return_value=runtime_artifacts
                ),
                app_runtime_artifact_finding=unittest.mock.Mock(
                    return_value=turbovasctl.finding(
                        "pass",
                        "feed-generation.app-artifacts",
                        "Mock runtime artifact identity matches.",
                    )
                ),
                app_compose_contract_finding=unittest.mock.Mock(
                    return_value=turbovasctl.finding(
                        "pass",
                        "feed-generation.app-compose",
                        "Mock Compose execution contract matches.",
                    )
                ),
                compose_command_with_app_images=unittest.mock.Mock(
                    return_value=["docker", "compose", "config"]
                ),
                run_command=unittest.mock.Mock(
                    return_value=subprocess.CompletedProcess([], 0, "", "")
                ),
            ):
                try:
                    result = turbovasctl.command_feed_generation_transition(
                        root,
                        target_id,
                        rollback=rollback,
                        allow_first_activation=allow_first_activation,
                        repair_attestation=repair_attestation,
                    )
                except MockTransitionInterruption as error:
                    result = error
        self.last_feed_journal_write = journal_write
        self.last_feed_database_attestation_write = database_attestation_write
        self.last_feed_database_attestation_read = database_attestation_read
        self.last_feed_runtime_restart = runtime_restart
        self.last_feed_phase_events = phase_events
        return result, selected, imported, stopped, cleared

    def test_feed_generation_activation_requires_first_activation_acknowledgement(self):
        result, selected, imported, stopped, _cleared = (
            self.run_mocked_feed_generation_transition(current_id=None)
        )
        self.assertEqual(result["status"], "fail")
        self.assertIn("acknowledgement", result["summary"])
        selected.assert_not_called()
        imported.assert_not_called()
        stopped.assert_not_called()

    def test_feed_generation_activation_selects_imports_and_verifies(self):
        result, selected, imported, stopped, cleared = (
            self.run_mocked_feed_generation_transition()
        )
        self.assertEqual(result["status"], "pass")
        self.assertIn("activation and import completed", result["summary"])
        self.assertEqual(selected.call_count, 1)
        imported.assert_called_once_with(
            unittest.mock.ANY,
            activation_managed=True,
            restart_services=False,
            app_image_ids=unittest.mock.ANY,
        )
        stopped.assert_called_once()
        cleared.assert_not_called()
        database_completed_at = self.last_feed_database_attestation_write.call_args.args[2]
        journal_payload = self.last_feed_journal_write.call_args_list[-1].args[1]
        self.assertEqual(journal_payload["completed_at"], database_completed_at)
        self.assertEqual(
            self.last_feed_database_attestation_write.call_args.args[1], "a" * 64
        )

